```javascript
// Constants
var TAU = 6.283;          // ≈ 2π
var PHI = 1.618;          // Golden ratio
var SQRT_HALF = 0.707;    // ≈ √(1/2)

// Configuration parameters
var config = {
  parameterA: 4000,       // Repulsion strength between nodes
  parameterB: 0.004,      // Default spring constant for edges
  parameterC: 0.92,       // Velocity damping/friction factor
  constantD: 0.0003,      // Centering gravity strength
  limitE: 40,             // Max number of particles
  rateF: 0.04,            // Particle drag rate
  valueG: 0.06            // Camera smoothing factor
};

// Nodes (graph vertices)
var nodes = [
  { id: "hub",       label: "Hub",        r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: "alpha",     label: "Alpha",      r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: "beta",      label: "Beta",       r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: "gamma",     label: "Gamma",      r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: "delta",     label: "Delta",      r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: "epsilon",   label: "Epsilon",    r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Edges (connections between nodes with rest lengths and spring constants)
var edges = [
  { a: "hub", b: "alpha",   rest: 160, k: 0.006 },
  { a: "hub", b: "beta",    rest: 160, k: 0.005 },
  { a: "hub", b: "gamma",   rest: 170, k: 0.004 },
  { a: "hub", b: "delta",   rest: 170, k: 0.004 },
  { a: "hub", b: "epsilon", rest: 180, k: 0.003 },
  { a: "alpha", b: "beta",    rest: 200, k: 0.002 },
  { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
  { a: "alpha", b: "epsilon", rest: 200, k: 0.002 }
];

// Camera state (smooth follow)
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// Particle system
var particles = [];
var frameCount = 0;

// Find a node by ID
function findNode(id) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// Physics simulation step
function simulate() {
  // 1. Node-to-node REPULSION (Coulomb-like force)
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var force = config.parameterA / (dist * dist);
      var fx = (dx / dist) * force;
      var fy = (dy / dist) * force;

      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // 2. Edge SPRING forces (Hooke's law)
  for (var e = 0; e < edges.length; e++) {
    var nodeA = findNode(edges[e].a);
    var nodeB = findNode(edges[e].b);
    if (!nodeA || !nodeB) continue;

    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = dist - edges[e].rest;
    var force = (edges[e].k || config.parameterB) * displacement;

    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // 3. Apply velocity, damping, and centering gravity
  for (var n = 0; n < nodes.length; n++) {
    // Damping (friction)
    nodes[n].vx *= config.parameterC;  // 0.92
    nodes[n].vy *= config.parameterC;

    // Centering gravity (pull toward 400, 300)
    nodes[n].vx += (400 - nodes[n].x) * config.constantD;
    nodes[n].vy += (300 - nodes[n].y) * config.constantD;

    // Update positions
    nodes[n].x += nodes[n].vx;
    nodes[n].y += nodes[n].vy;
  }
}

// Spawn a new particle from a random node
function spawnParticle() {
  if (particles.length >= config.limitE) return;  // Max 40 particles

  var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
  var angle = Math.random() * TAU;
  var speed = 0.3 + Math.random() * SQRT_HALF;

  particles.push({
    x: sourceNode.x,
    y: sourceNode.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * PHI * SQRT_HALF  // 0.8 to ~1.94
  });
}

// Update and cull particles
function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var p = particles[i];
    p.vx *= 1 - config.rateF * 0.125;   // Slight drag
    p.vy *= 1 - config.rateF * 0.125;
    p.x += p.vx;
    p.y += p.vy;
    p.age++;
    if (p.age > p.maxAge) particles.splice(i, 1);  // Remove dead particles
  }
}

// Smooth camera follow
function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * config.valueG;
  camera.y += (cameraTarget.y - camera.y) * config.valueG;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * config.valueG;
}

// Main loop tick
function tick() {
  simulate();
  updateParticles();
  updateCamera();
  if (frameCount % 3 === 0) spawnParticle();  // Spawn particle every 3rd frame
  frameCount++;
}

// Run at ~60fps (16ms interval)
setInterval(tick, 16);
```

## What It Does

This is a **force-directed graph layout simulation** with a particle effect system. Specifically:

### 🔵 Force-Directed Graph
- **6 nodes** ("Hub", "Alpha", "Beta", "Gamma", "Delta", "Epsilon") connected by **8 edges**
- Uses classic force-directed physics:
  - **Repulsive forces** between all node pairs (inverse-square law, like electrical charges)
  - **Spring forces** along edges (Hooke's law, pulling connected nodes toward a rest distance)
  - **Centering gravity** pulling everything toward (400, 300)
  - **Velocity damping** (0.92 multiplier) to prevent oscillation

### ✨ Particle System
- Every 3 frames, a particle spawns from a random node
- Particles drift outward with slight drag, fade after 800–2000 frames
- Capped at 40 particles — creates a decorative ambient effect

### 🎥 Smooth Camera
- Camera position and zoom lerp toward a target at 6% per frame — classic smooth follow

**In summary**: This is the **physics engine** (no rendering code) for an interactive node-graph visualization with decorative floating particles, likely rendered elsewhere on an HTML canvas.
